    metadata_ratio = 0
    for msg in messages.data:
        if msg.role == "assistant":
            content_len = len(msg.content[0].text.value)
            metadata_indicators = len([w for w in msg.content[0].text.value.split() 
                                    if any(x in w.lower() for x in ['azure', 'permission', 'timestamp', 'etag'])])
            if content_len > 0:
                metadata_ratio += metadata_indicators / content_len

