import { AzureSearchAgentExtension } from "@azure/ai-projects";

const searchExtension = new AzureSearchAgentExtension({
  endpoint: process.env.SEARCH_ENDPOINT!,
  key: process.env.SEARCH_KEY!
});

async function budgetedRetrieval(query: string, maxTokens: number = 4000): Promise<string> {
  const results = await searchExtension.search(query, {
    top: 3,
    queryType: "semantic",
    semanticConfiguration: "default"
  });

  let content = "";
  for (const result of results.results) {
    const docContent = result.document.content || result.document.chunk;
    const docTokens = estimateTokens(docContent);

    if (content.length + docTokens < maxTokens) {
      content += `\n--- Source: ${result.document.metadata.filename} ---\n${docContent}`;
    } else {
      break;
    }
  }

  return content;
}

// Integrate with agent
agent.addExtension(searchExtension);
agent.instructions = `Always use budgetedRetrieval for grounding data.`;
